formatDate.code:
export function formatDate(dateString: string): string {
  const date = new Date(dateString);
  return date.toLocaleDateString('en-CA', {
    year: 'numeric',
    month: 'short',
    day: 'numeric'
  });
}

formatRelativeDate.code:
export function formatRelativeDate(dateString: string): string {
  const date = new Date(dateString);
  const now = new Date();
  const diffMs = date.getTime() - now.getTime();
  const diffDays = Math.ceil(diffMs / (1000 * 60 * 60 * 24));

  if (diffDays === 0) return 'Today';
  if (diffDays === 1) return 'Tomorrow';
  if (diffDays === -1) return 'Yesterday';
  if (diffDays > 0) return `In ${diffDays} days`;
  return `${Math.abs(diffDays)} days ago`;
}

isOverdue.code:
export function isOverdue(dateString: string): boolean {
  const date = new Date(dateString);
  const now = new Date();
  return date < now;
}

getStatusBadgeProps.code:
export function getStatusBadgeProps(status: string) {
  const map: Record<string, { type: string; content: string }> = {
    'assigned': { type: 'information', content: 'Assigned' },
    'in-progress': { type: 'important', content: 'In Progress' },
    'pending': { type: 'inactive', content: 'Pending' },
    'complete': { type: 'success', content: 'Complete' }
  };
  return map[status] || { type: 'inactive', content: status };
}

getPriorityBadgeProps.code:
export function getPriorityBadgeProps(priority: 'high' | 'medium' | 'low') {
  const map = {
    high: { type: 'emergency', content: 'High' },
    medium: { type: 'important', content: 'Medium' },
    low: { type: 'archived', content: 'Low' }
  };
  return map[priority];
}

